const { Client } = require('ssh2');

const backupScript = Buffer.from(`#!/bin/bash
# /root/universo-backup.sh
# Auto-generated by Antigravity

set -e

BACKUP_DIR="/var/backups/universomerchan"
LOG_FILE="/var/log/universo-backup.log"
DATE=$(date +%Y-%m-%d-%H%M)
DB_NAME="universomerchan"
DB_USER="universo"
export PGPASSWORD="UmErch2026Pg"

echo "[$(date)] Starting backup process..." >> $LOG_FILE

mkdir -p $BACKUP_DIR

# 1. Volcado de Base de Datos
echo "[$(date)] Dumping database..." >> $LOG_FILE
pg_dump -U $DB_USER -h localhost -F c $DB_NAME > /tmp/db-$DATE.dump

# 2. Comprimir todo (DB + Uploads públicos)
echo "[$(date)] Compressing files to $BACKUP_DIR/backup-$DATE.tar.gz" >> $LOG_FILE
tar -czf $BACKUP_DIR/backup-$DATE.tar.gz /tmp/db-$DATE.dump /var/www/universomerchan/public/uploads /var/www/universomerchan/uploads 2>> $LOG_FILE || true

# Limpiar temporal
rm -f /tmp/db-$DATE.dump

# 3. Borrar copias de más de 7 días
echo "[$(date)] Pruning old backups..." >> $LOG_FILE
find $BACKUP_DIR -name "backup-*.tar.gz" -type f -mtime +7 -exec rm {} \\;

echo "[$(date)] Backup successful!" >> $LOG_FILE
`).toString('base64');

const conn = new Client();
console.log("Connecting to VPS...");

conn.on('ready', () => {
    const cmds = [
        `echo "${backupScript}" | base64 -d > /root/universo-backup.sh`,
        `chmod +x /root/universo-backup.sh`,
        `mkdir -p /var/backups/universomerchan`,
        `(crontab -l 2>/dev/null | grep -v "universo-backup.sh" ; echo "0 4 * * * /root/universo-backup.sh") | crontab -`,
        `cat /root/universo-backup.sh | head -n 5` // Verificamos
    ];

    conn.exec(cmds.join(' && '), (err, stream) => {
        if (err) throw err;
        stream.on('close', (code) => {
            console.log("Exit code:", code);
            conn.end();
        }).on('data', (d) => process.stdout.write(d))
          .stderr.on('data', (d) => process.stderr.write(d));
    });
}).connect({
    host: '212.227.90.110', 
    port: 22, 
    username: 'root', 
    password: 'V34a6df?6'
});
